   364→// Build bundles the target directory Flipt feature state into the target configured on the Store
   365→// It returns a Bundle which contains metadata regarding the resulting bundle details
   366→func (s *Store) Build(ctx context.Context, src fs.FS, ref Reference) (Bundle, error) {
   367→	store, err := s.getTarget(ref)
   368→	if err != nil {
   369→		return Bundle{}, err
   370→	}
   371→
   372→	layers, err := s.buildLayers(ctx, store, src)
   373→	if err != nil {
   374→		return Bundle{}, err
   375→	}
   376→
   377→	desc, err := oras.PackManifest(ctx, store, s.opts.manifestVersion, MediaTypeFliptFeatures, oras.PackManifestOptions{
   378→		ManifestAnnotations: map[string]string{},
   379→		Layers:              layers,
   380→	})
   381→	if err != nil {
   382→		return Bundle{}, err
   383→	}
   384→
   385→	if ref.Reference.Reference != "" {
   386→		if err := store.Tag(ctx, desc, ref.Reference.Reference); err != nil {
   387→			return Bundle{}, err
   388→		}
   389→	}
   390→
   391→	bundle := Bundle{
   392→		Digest:     desc.Digest,
   393→		Repository: ref.Repository,
   394→		Tag:        ref.Reference.Reference,
   395→	}
   396→
   397→	bundle.CreatedAt, err = parseCreated(desc.Annotations)
   398→	if err != nil {
   399→		return Bundle{}, err
   400→	}
   401→
   402→	return bundle, nil
   403→}
