   405→func (s *Store) buildLayers(ctx context.Context, store oras.Target, src fs.FS) (layers []v1.Descriptor, _ error) {
   406→	if err := storagefs.WalkDocuments(s.logger, src, func(doc *ext.Document) error {
   407→		payload, err := json.Marshal(&doc)
   408→		if err != nil {
   409→			return err
   410→		}
   411→
   412→		desc := v1.Descriptor{
   413→			Digest:    digest.FromBytes(payload),
   414→			Size:      int64(len(payload)),
   415→			MediaType: MediaTypeFliptNamespace,
   416→			Annotations: map[string]string{
   417→				AnnotationFliptNamespace: doc.Namespace,
   418→			},
   419→		}
   420→
   421→		s.logger.Debug("adding layer", zap.String("digest", desc.Digest.Hex()), zap.String("namespace", doc.Namespace))
   422→
   423→		if err := store.Push(ctx, desc, bytes.NewReader(payload)); err != nil && !errors.Is(err, errdef.ErrAlreadyExists) {
   424→			return err
   425→		}
   426→
   427→		layers = append(layers, desc)
   428→		return nil
   429→	}); err != nil {
   430→		return nil, err
   431→	}
   432→	return layers, nil
   433→}
