   435→func (s *Store) Copy(ctx context.Context, src, dst Reference) (Bundle, error) {
   436→	if src.Reference.Reference == "" {
   437→		return Bundle{}, fmt.Errorf("source bundle: %w", ErrReferenceRequired)
   438→	}
   439→
   440→	if dst.Reference.Reference == "" {
   441→		return Bundle{}, fmt.Errorf("destination bundle: %w", ErrReferenceRequired)
   442→	}
   443→
   444→	srcTarget, err := s.getTarget(src)
   445→	if err != nil {
   446→		return Bundle{}, err
   447→	}
   448→
   449→	dstTarget, err := s.getTarget(dst)
   450→	if err != nil {
   451→		return Bundle{}, err
   452→	}
   453→
   454→	desc, err := oras.Copy(
   455→		ctx,
   456→		srcTarget,
   457→		src.Reference.Reference,
   458→		dstTarget,
   459→		dst.Reference.Reference,
   460→		oras.DefaultCopyOptions)
   461→	if err != nil {
   462→		return Bundle{}, err
   463→	}
   464→
   465→	rd, err := dstTarget.Fetch(ctx, desc)
   466→	if err != nil {
   467→		return Bundle{}, err
   468→	}
   469→
   470→	var man v1.Manifest
   471→	if err := json.NewDecoder(rd).Decode(&man); err != nil {
   472→		return Bundle{}, err
   473→	}
   474→
   475→	bundle := Bundle{
   476→		Digest:     desc.Digest,
   477→		Repository: dst.Repository,
   478→		Tag:        dst.Reference.Reference,
   479→	}
   480→
   481→	bundle.CreatedAt, err = parseCreated(man.Annotations)
   482→	if err != nil {
   483→		return Bundle{}, err
   484→	}
   485→
   486→	return bundle, nil
   487→}
