   296→// Bundle is a record of an existing Flipt feature bundle
   297→type Bundle struct {
   298→	Digest     digest.Digest
   299→	Repository string
   300→	Tag        string
   301→	CreatedAt  time.Time
   302→}
   303→
   304→// List returns a slice of bundles available on the host
   305→func (s *Store) List(ctx context.Context) (bundles []Bundle, _ error) {
   306→	fi, err := os.Open(s.opts.bundleDir)
   307→	if err != nil {
   308→		return nil, err
   309→	}
   310→
   311→	defer fi.Close()
   312→
   313→	entries, err := fi.ReadDir(-1)
   314→	if err != nil {
   315→		return nil, err
   316→	}
   317→
   318→	for _, entry := range entries {
   319→		bytes, err := os.ReadFile(filepath.Join(s.opts.bundleDir, entry.Name(), v1.ImageIndexFile))
   320→		if err != nil {
   321→			if errors.Is(err, os.ErrNotExist) {
   322→				return nil, nil
   323→			}
   324→
   325→			return nil, err
   326→		}
   327→
   328→		var index v1.Index
   329→		if err := json.Unmarshal(bytes, &index); err != nil {
   330→			return nil, err
   331→		}
   332→
   333→		for _, manifest := range index.Manifests {
   334→			digest := manifest.Digest
   335→			path := filepath.Join(s.opts.bundleDir, entry.Name(), "blobs", digest.Algorithm().String(), digest.Hex())
   336→			bytes, err := os.ReadFile(path)
   337→			if err != nil {
   338→				return nil, err
   339→			}
   340→
   341→			var man v1.Manifest
   342→			if err := json.Unmarshal(bytes, &man); err != nil {
   343→				return nil, err
   344→			}
   345→
   346→			bundle := Bundle{
   347→				Digest:     manifest.Digest,
   348→				Repository: entry.Name(),
   349→				Tag:        manifest.Annotations[v1.AnnotationRefName],
   350→			}
   351→
   352→			bundle.CreatedAt, err = parseCreated(man.Annotations)
   353→			if err != nil {
   354→				return nil, err
   355→			}
   356→
   357→			bundles = append(bundles, bundle)
   358→		}
   359→	}
   360→
   361→	return
   362→}
