   435→func (s *Store) Copy(ctx context.Context, src, dst Reference) (Bundle, error) {
   436→	if src.Reference.Reference == "" {
   437→		return Bundle{}, fmt.Errorf("source bundle: %w", ErrReferenceRequired)
   438→	}
   439→
   440→	if dst.Reference.Reference == "" {
   441→		return Bundle{}, fmt.Errorf("destination bundle: %w", ErrReferenceRequired)
   442→	}
   443→
   444→	srcTarget, err := s.getTarget(src)
   445→	if err != nil {
   446→		return Bundle{}, err
   447→	}
   448→
   449→	dstTarget, err := s.getTarget(dst)
   450→	if err != nil {
   451→		return Bundle{}, err
   452→	}
   453→
   454→	desc, err := oras.Copy(
   455→		ctx,
   456→		srcTarget,
   457→		src.Reference.Reference,
   458→		dstTarget,
   459→		dst.Reference.Reference,
   460→		oras.DefaultCopyOptions)
   461→	if err != nil {
   462→		return Bundle{}, err
   463→	}
