func (p *awsCredentialProvider) Credential(ctx context.Context, hostname string) (auth.Credential, error) {
	// For now, return the fallback credential (static username/password)
	// In the future, this could be enhanced to fetch ECR-specific tokens
	if p.fallback.Username != "" || p.fallback.Password != "" {
		return p.fallback, nil
	}
	return auth.EmptyCredential, nil
}

// StoreOptions are used to configure call to NewStore
// This shouldn't be handled directory, instead use one of the function options
// e.g. WithBundleDir or WithCredentials
type StoreOptions struct {
	bundleDir       string
	manifestVersion oras.PackManifestVersion
	auth            *struct {
		username string
		password string
	}
	awsProvider *struct {
		enabled  bool
		fallback *struct {
			username string
			password string
		}
	}
}

// WithCredentials configures username and password credentials used for authenticating
// with remote registries
func WithCredentials(user, pass string) containers.Option[StoreOptions] {
