// WithAWSProvider configures AWS credentials chain for authenticating with remote registries
// When enabled, AWS credentials from the credentials chain (environment variables, IAM roles, etc.)
// will be used. If AWS credentials are not available, it falls back to static credentials.
func WithAWSProvider(enabled bool, fallbackUser, fallbackPass string) containers.Option[StoreOptions] {
