const (
	SchemeHTTP  = "http"
	SchemeHTTPS = "https"
	SchemeFlipt = "flipt"
)

// Store is a type which can retrieve Flipt feature files from a target repository and reference
// Repositories can be local (OCI layout directories on the filesystem) or a remote registry
type Store struct {
	opts   StoreOptions
	logger *zap.Logger
	local  oras.Target
}

// awsCredentialProvider implements auth.CredentialProvider for AWS ECR
// It dynamically fetches credentials from the AWS credentials chain
type awsCredentialProvider struct {
	logger       *zap.Logger
	awsConfig    aws.Config
	fallback     auth.Credential
	mu           sync.Mutex
	lastToken    string
	lastTokenExp time.Time
}

// Credential fetches AWS ECR authorization token for the given registry
func (p *awsCredentialProvider) Credential(ctx context.Context, hostname string) (auth.Credential, error) {
	// For now, return the fallback credential (static username/password)
	// In the future, this could be enhanced to fetch ECR-specific tokens
	if p.fallback.Username != "" || p.fallback.Password != "" {
		return p.fallback, nil
	}
	return auth.EmptyCredential, nil
}

// StoreOptions are used to configure call to NewStore
// This shouldn't be handled directory, instead use one of the function options
// e.g. WithBundleDir or WithCredentials
type StoreOptions struct {
	bundleDir       string
	manifestVersion oras.PackManifestVersion
	auth            *struct {
		username string
		password string
	}
	awsProvider *struct {
		enabled  bool
		fallback *struct {
			username string
			password string
		}
	}
}

// WithCredentials configures username and password credentials used for authenticating
// with remote registries
func WithCredentials(user, pass string) containers.Option[StoreOptions] {
	return func(so *StoreOptions) {
		so.auth = &struct {
			username string
			password string
		}{
			username: user,
			password: pass,
		}
	}
}

// WithAWSProvider configures AWS credentials chain for authenticating with remote registries
// When enabled, AWS credentials from the credentials chain (environment variables, IAM roles, etc.)
// will be used. If AWS credentials are not available, it falls back to static credentials.
func WithAWSProvider(enabled bool, fallbackUser, fallbackPass string) containers.Option[StoreOptions] {
	return func(so *StoreOptions) {
		so.awsProvider = &struct {
			enabled  bool
			fallback *struct {
				username string
				password string
			}
		}{
			enabled: enabled,
			fallback: &struct {
				username string
				password string
			}{
				username: fallbackUser,
				password: fallbackPass,
			},
		}
	}
}

// WithManifestVersion configures what OCI Manifest version to build the bundle.
func WithManifestVersion(version oras.PackManifestVersion) containers.Option[StoreOptions] {
	return func(s *StoreOptions) {
		s.manifestVersion = version
	}
}

// NewStore constructs and configures an instance of *Store for the provided config
func NewStore(logger *zap.Logger, dir string, opts ...containers.Option[StoreOptions]) (*Store, error) {
	store := &Store{
		opts: StoreOptions{
			bundleDir:       dir,
			manifestVersion: oras.PackManifestVersion1_1,
		},
		logger: logger,
		local:  memory.New(),
	}

	containers.ApplyAll(&store.opts, opts...)

	return store, nil
}

type Reference struct {
	registry.Reference
	Scheme string
}

func ParseReference(repository string) (Reference, error) {
	scheme, repository, match := strings.Cut(repository, "://")
	// support empty scheme as remote and https
	if !match {
		repository = scheme
		scheme = SchemeHTTPS
	}

	if !strings.Contains(repository, "/") {
		repository = "local/" + repository
		scheme = SchemeFlipt
	}

	ref, err := registry.ParseReference(repository)
	if err != nil {
		return Reference{}, err
	}

	switch scheme {
	case SchemeHTTP, SchemeHTTPS:
	case SchemeFlipt:
		if ref.Registry != "local" {
			return Reference{}, fmt.Errorf("unexpected local reference: %q", ref)
		}
	default:
		return Reference{}, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", scheme)
	}

	return Reference{
		Reference: ref,
		Scheme:    scheme,
	}, nil
}

func (s *Store) getTarget(ref Reference) (oras.Target, error) {
	switch ref.Scheme {
	case SchemeHTTP, SchemeHTTPS:
		remote, err := remote.NewRepository(fmt.Sprintf("%s/%s", ref.Registry, ref.Repository))
		if err != nil {
			return nil, err
		}

		remote.PlainHTTP = ref.Scheme == "http"

		// Set up authentication
		if s.opts.awsProvider != nil && s.opts.awsProvider.enabled {
			// Use AWS credentials provider with fallback
			fallbackCred := auth.Credential{
				Username: s.opts.awsProvider.fallback.username,
				Password: s.opts.awsProvider.fallback.password,
			}

			// Try to load AWS config for credentials
			awsCfg, err := config.LoadDefaultConfig(context.Background())
			if err != nil {
				s.logger.Warn("failed to load AWS config, falling back to static credentials",
					ZapError("error", err))
				// Fall back to static credentials
				if s.opts.awsProvider.fallback.username != "" || s.opts.awsProvider.fallback.password != "" {
					remote.Client = &auth.Client{
						Credential: auth.StaticCredential(ref.Registry, fallbackCred),
					}
				}
			} else {
				// Create AWS credential provider
				remote.Client = &auth.Client{
