	layers, err := s.buildLayers(ctx, store, src)
	if err != nil {
		return Bundle{}, err
	}

	desc, err := oras.PackManifest(ctx, store, s.opts.manifestVersion, MediaTypeFliptFeatures, oras.PackManifestOptions{
		ManifestAnnotations: map[string]string{},
		Layers:              layers,
	})
	if err != nil {
