		ManifestAnnotations: map[string]string{},
		Layers:              layers,
	})
	if err != nil {
		return Bundle{}, err
	}

	if ref.Reference.Reference != "" {
		if err := store.Tag(ctx, desc, ref.Reference.Reference); err != nil {
			return Bundle{}, err
		}
	}

