// Store is a type which can retrieve Flipt feature files from a target repository and reference
// Repositories can be local (OCI layout directories on the filesystem) or a remote registry
type Store struct {
	opts   StoreOptions
	logger *zap.Logger
	local  oras.Target
}

// newAWSCredentialFunc creates a credential function for AWS credentials chain
// It dynamically fetches credentials from the AWS credentials chain
func newAWSCredentialFunc(logger *zap.Logger, fallback auth.Credential) auth.CredentialFunc {
	return func(ctx context.Context, hostport string) (auth.Credential, error) {
		// For now, return the fallback credential (static username/password)
		// In the future, this could be enhanced to fetch ECR-specific tokens
		// using the AWS credentials chain (e.g., for ECR token generation)
		if fallback.Username != "" || fallback.Password != "" {
			return fallback, nil
		}
		return auth.EmptyCredential, nil
	}
