// Store is a type which can retrieve Flipt feature files from a target repository and reference
// Repositories can be local (OCI layout directories on the filesystem) or a remote registry
type Store struct {
	opts   StoreOptions
	logger *zap.Logger
	local  oras.Target
}

// newAWSCredentialFunc creates a credential function for AWS credentials chain
// It dynamically fetches credentials from the AWS credentials chain
func newAWSCredentialFunc(logger *zap.Logger, fallback auth.Credential) auth.CredentialFunc {
	return func(ctx context.Context, hostport string) (auth.Credential, error) {
		// For now, return the fallback credential (static username/password)
		// In the future, this could be enhanced to fetch ECR-specific tokens
		// using the AWS credentials chain (e.g., for ECR token generation)
		if fallback.Username != "" || fallback.Password != "" {
			return fallback, nil
		}
		return auth.EmptyCredential, nil
	}
}

// StoreOptions are used to configure call to NewStore
// This shouldn't be handled directory, instead use one of the function options
// e.g. WithBundleDir or WithCredentials
type StoreOptions struct {
	bundleDir       string
	manifestVersion oras.PackManifestVersion
	auth            *struct {
		username string
		password string
	}
	awsProvider *struct {
		enabled  bool
		fallback *struct {
			username string
			password string
		}
	}
}

// WithCredentials configures username and password credentials used for authenticating
// with remote registries
func WithCredentials(user, pass string) containers.Option[StoreOptions] {
	return func(so *StoreOptions) {
		so.auth = &struct {
			username string
			password string
		}{
			username: user,
			password: pass,
		}
	}
}

// WithAWSProvider configures AWS credentials chain for authenticating with remote registries
// When enabled, AWS credentials from the credentials chain (environment variables, IAM roles, etc.)
// will be used. If AWS credentials are not available, it falls back to static credentials.
func WithAWSProvider(enabled bool, fallbackUser, fallbackPass string) containers.Option[StoreOptions] {
	return func(so *StoreOptions) {
		so.awsProvider = &struct {
			enabled  bool
			fallback *struct {
				username string
				password string
			}
		}{
			enabled: enabled,
			fallback: &struct {
				username string
				password string
			}{
				username: fallbackUser,
				password: fallbackPass,
			},
		}
	}
