func NewStore(logger *zap.Logger, dir string, opts ...containers.Option[StoreOptions]) (*Store, error) {
	store := &Store{
		opts: StoreOptions{
			bundleDir:       dir,
			manifestVersion: oras.PackManifestVersion1_1,
		},
		logger: logger,
		local:  memory.New(),
