type Reference struct {
	registry.Reference
	Scheme string
}

func ParseReference(repository string) (Reference, error) {
	scheme, repository, match := strings.Cut(repository, "://")
	// support empty scheme as remote and https
	if !match {
		repository = scheme
		scheme = SchemeHTTPS
	}

	if !strings.Contains(repository, "/") {
		repository = "local/" + repository
		scheme = SchemeFlipt
	}

	ref, err := registry.ParseReference(repository)
	if err != nil {
		return Reference{}, err
	}

	switch scheme {
	case SchemeHTTP, SchemeHTTPS:
	case SchemeFlipt:
		if ref.Registry != "local" {
			return Reference{}, fmt.Errorf("unexpected local reference: %q", ref)
		}
	default:
		return Reference{}, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", scheme)
	}

	return Reference{
		Reference: ref,
		Scheme:    scheme,
	}, nil
}

func (s *Store) getTarget(ref Reference) (oras.Target, error) {
	switch ref.Scheme {
	case SchemeHTTP, SchemeHTTPS:
		remote, err := remote.NewRepository(fmt.Sprintf("%s/%s", ref.Registry, ref.Repository))
		if err != nil {
			return nil, err
		}

		remote.PlainHTTP = ref.Scheme == "http"

		// Set up authentication
		if s.opts.awsProvider != nil && s.opts.awsProvider.enabled {
			// Use AWS credentials provider with fallback
			fallbackCred := auth.Credential{
				Username: s.opts.awsProvider.fallback.username,
				Password: s.opts.awsProvider.fallback.password,
			}

			// Try to load AWS config for credentials
			_, err := config.LoadDefaultConfig(context.Background())
			if err != nil {
				s.logger.Warn("failed to load AWS config, falling back to static credentials",
					zap.Error(err))
			}

			// Create AWS credential provider function
			credFunc := newAWSCredentialFunc(s.logger, fallbackCred)
			remote.Client = &auth.Client{
				Credential: credFunc,
			}
		} else if s.opts.auth != nil {
			remote.Client = &auth.Client{
				Credential: auth.StaticCredential(ref.Registry, auth.Credential{
					Username: s.opts.auth.username,
					Password: s.opts.auth.password,
				}),
			}
		}

		return remote, nil
	case SchemeFlipt:
		// build the store once to ensure it is valid
		store, err := oci.New(path.Join(s.opts.bundleDir, ref.Repository))
		if err != nil {
			return nil, err
		}

		store.AutoSaveIndex = true

		return store, nil
	}

	return nil, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", ref.Scheme)
}

